class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        indices = []
        a_indices = [i for i in range(len(s)) if s.startswith(a, i)]
        b_indices = [i for i in range(len(s)) if s.startswith(b, i)]
        for i in a_indices:
            for j in b_indices:
                if abs(i - j) <= k:
                    indices.append(i)
                    break
        return sorted(set(indices))
